import{_ as a,o as i,c as o,ag as s}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Coordinación de protecciones","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-systems/protection/coordination-of-protections.md","filePath":"es/power-systems/protection/coordination-of-protections.md"}'),r={name:"es/power-systems/protection/coordination-of-protections.md"};function n(c,e,t,l,d,p){return i(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="coordinacion-de-protecciones" tabindex="-1">Coordinación de protecciones <a class="header-anchor" href="#coordinacion-de-protecciones" aria-label="Permalink to &quot;Coordinación de protecciones&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>La coordinación de protecciones es el proceso de organizar y configurar los dispositivos de protección para que solo opere el dispositivo más cercano a una falla.</p><p>Asegura que las fallas se aíslen localmente sin interrumpir innecesariamente la energía al resto del sistema.</p><p>La coordinación adecuada es esencial para mantener la confiabilidad del sistema y minimizar el tiempo de inactividad.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de la coordinación es:</p><ul><li>Aislar fallas con impacto mínimo en el sistema general</li><li>Mantener la continuidad del servicio para las cargas no afectadas</li><li>Reducir el estrés del equipo limitando la duración de la falla</li><li>Asegurar operación predecible y controlada de los dispositivos de protección</li></ul><p>Sin coordinación, una sola falla puede provocar que grandes porciones de una instalación pierdan energía.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Los dispositivos de protección se seleccionan y ajustan utilizando curvas tiempo-corriente.</p><p>Cada dispositivo se configura para operar a un nivel de corriente específico y con un retardo de tiempo determinado.</p><p>El principio de coordinación se basa en la jerarquía:</p><ul><li>Los dispositivos aguas abajo operan primero para fallas locales</li><li>Los dispositivos aguas arriba actúan como respaldo si la protección aguas abajo falla</li></ul><p>Esto se logra mediante:</p><ul><li>Configurar umbrales de disparo más bajos en dispositivos aguas abajo</li><li>Introducir retardos de tiempo intencionales en dispositivos aguas arriba</li></ul><p>Gráficamente, la coordinación a menudo se verifica utilizando curvas tiempo-corriente para asegurar la separación entre dispositivos.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>La coordinación se aplica en:</p><ul><li>Paneles de distribución y tableros de distribución en baja tensión</li><li>Switchgear (celdas de media tensión) y sistemas de alimentadores</li><li>Circuitos de control de motores</li><li>Esquemas de protección de transformadores</li><li>Instalaciones industriales con múltiples niveles de distribución</li></ul><p>Es requerida donde múltiples dispositivos de protección están conectados en serie.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Selectividad</strong><br> Los dispositivos deben operar en la secuencia correcta sin superposición</p></li><li><p><strong>Curvas tiempo-corriente</strong><br> El espaciado adecuado entre curvas asegura coordinación bajo diferentes condiciones de falla</p></li><li><p><strong>Tipos de dispositivos</strong><br> Mezclar fusibles e interruptores automáticos requiere una comparación cuidadosa de características</p></li><li><p><strong>Configuración del sistema</strong><br> Los sistemas radiales y en lazo requieren enfoques de coordinación diferentes</p></li><li><p><strong>Protección de respaldo</strong><br> Los dispositivos aguas arriba deben operar aún si los dispositivos aguas abajo fallan</p></li><li><p><strong>Cambios en el sistema</strong><br> Agregar cargas o equipo puede requerir re-coordinación</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>La coordinación perfecta puede no ser siempre posible, especialmente a altos niveles de falla</li><li>La sobre-coordinación puede resultar en tiempos de despeje de falla más lentos</li><li>La sub-coordinación provoca interrupciones innecesarias</li><li>La documentación de configuraciones es crítica para mantenimiento y diagnóstico</li><li>Los estudios de coordinación deben actualizarse cuando el sistema cambia</li></ul>',25)])])}const f=a(r,[["render",n]]);export{m as __pageData,f as default};
